interface.definition:
a!localVariables(
  local!event: #"_a-0000ee09-79c9-8000-9bf0-011c48011c48_1477251"(id: ri!eventId),
  #"SYSTEM_SYSRULES_formLayout_v2"(
    titleBar: #"urn:appian:translation-string:v1:69d9f449-ed16-4516-95bf-baf8dd76061b" & ": " & local!event[#"urn:appian:record-field:v1:fa952da3-a305-45ce-924b-89ca2dab3222/7bd3ce80-0696-4abd-a32c-6f6f775a9f5d"],
    showTitleBarDivider: true,
    showButtonDivider: true,
    contents: {
      #"SYSTEM_SYSRULES_columnsLayout"(
        columns: {
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {},
            width: "1X"
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            width: "10X",
            contents: {
              #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1525034"(
                documents: ri!documents,
                showWhen: true,
                allowedFileTypes: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1524665",
              )
            }
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {},
            width: "1X"
          )
        }
      )
    },
    buttons: #"SYSTEM_SYSRULES_ButtonLayout"(
      primaryButtons: {
        #"SYSTEM_SYSRULES_buttonWidget_v1"(
          label: #"urn:appian:translation-string:v1:d545b4d7-64e0-47d0-9e5c-c33324eed3d3",
          submit: true,
          style: "SOLID",
          disabled: a!isNullOrEmpty(ri!documents)
        )
      },
      secondaryButtons: {
        #"SYSTEM_SYSRULES_buttonWidget_v1"(
          label: #"urn:appian:translation-string:v1:d940fe67-4bc0-43d9-9eca-be0aa0394b8a",
          value: true,
          saveInto: ri!cancel,
          submit: true,
          style: "OUTLINE",
          validate: false
        )
      }
    )
  )
)
